namespace sv_c74f07881dc3443fad6c2b5ae14ac864;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);

public record NotificationPrefs(
    bool EmailNotifications,
    bool PushNotifications,
    bool WeeklyDigest,
    List<string> MutedChannels);

public record SecuritySettings(
    bool TwoFactorEnabled,
    DateTime? LastPasswordChange,
    List<ActiveSession> Sessions);

public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);

public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

namespace sv_c74f07881dc3443fad6c2b5ae14ac864.Services;

public class MockSettingsService : ISettingsService
{
    private UserProfile _profile = new(
        "Jane Doe",
        "jane.doe@example.com",
        "https://i.pravatar.cc/150?img=5",
        "Software engineer passionate about building great user experiences.");

    private NotificationPrefs _notificationPrefs = new(
        EmailNotifications: true,
        PushNotifications: true,
        WeeklyDigest: false,
        MutedChannels: ["Marketing"]);

    private SecuritySettings _security = new(
        TwoFactorEnabled: false,
        LastPasswordChange: DateTime.UtcNow.AddDays(-45),
        Sessions:
        [
            new("sess-1", "Chrome on Windows", "New York, US", DateTime.UtcNow.AddMinutes(-5)),
            new("sess-2", "Safari on iPhone", "New York, US", DateTime.UtcNow.AddHours(-2)),
            new("sess-3", "Firefox on macOS", "London, UK", DateTime.UtcNow.AddDays(-3)),
        ]);

    private AppearanceSettings _appearance = new("Light", "Medium", "English", false);

    public Task<UserProfile> GetProfileAsync() =>
        Task.FromResult(_profile);

    public Task SaveProfileAsync(UserProfile profile)
    {
        _profile = profile;
        return Task.CompletedTask;
    }

    public Task<NotificationPrefs> GetNotificationPrefsAsync() =>
        Task.FromResult(_notificationPrefs);

    public Task SaveNotificationPrefsAsync(NotificationPrefs prefs)
    {
        _notificationPrefs = prefs;
        return Task.CompletedTask;
    }

    public Task<SecuritySettings> GetSecuritySettingsAsync() =>
        Task.FromResult(_security);

    public Task ChangePasswordAsync(string currentPassword, string newPassword)
    {
        _security = _security with { LastPasswordChange = DateTime.UtcNow };
        return Task.CompletedTask;
    }

    public Task RevokeSessionAsync(string sessionId)
    {
        _security = _security with
        {
            Sessions = _security.Sessions.Where(s => s.Id != sessionId).ToList()
        };
        return Task.CompletedTask;
    }

    public Task<AppearanceSettings> GetAppearanceAsync() =>
        Task.FromResult(_appearance);

    public Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        _appearance = settings;
        return Task.CompletedTask;
    }
}

@* Vertical tab navigation for settings sections *@

<nav class="settings-sidebar">
    <ul class="nav flex-column">
        @foreach (var section in _sections)
        {
            <li class="nav-item">
                <button class="nav-link @(ActiveSection == section.Key ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="sidebar-icon">@section.Icon</span>
                    <span>@section.Label</span>
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired]
    public string ActiveSection { get; set; } = "";

    [Parameter, EditorRequired]
    public EventCallback<string> OnSectionChanged { get; set; }

    private readonly record struct SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] _sections =
    [
        new("Profile", "Profile", "👤"),
        new("Notifications", "Notifications", "🔔"),
        new("Security", "Security", "🔒"),
        new("Appearance", "Appearance", "🎨"),
    ];
}

.settings-sidebar {
    min-width: 220px;
    background: var(--bs-body-bg);
    border-right: 1px solid var(--bs-border-color);
    padding: 1rem 0;
}

.nav-link {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.25rem;
    color: var(--bs-body-color);
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    border-left: 3px solid transparent;
    cursor: pointer;
    transition: background-color 0.15s, border-color 0.15s;
}

.nav-link:hover {
    background-color: var(--bs-tertiary-bg);
}

.nav-link.active {
    background-color: var(--bs-primary-bg-subtle);
    border-left-color: var(--bs-primary);
    color: var(--bs-primary);
    font-weight: 600;
}

.sidebar-icon {
    font-size: 1.15rem;
}

@inject ISettingsService SettingsService

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center"
         role="button"
         @onclick="ToggleExpanded">
        <span>🔑 Change Password</span>
        <span class="expand-icon">@(_expanded ? "▲" : "▼")</span>
    </div>

    @if (_expanded)
    {
        <div class="card-body">
            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible" role="alert">
                    @_message
                    <button type="button" class="btn-close" @onclick="() => _message = null"></button>
                </div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _message;
    private bool _isError;
    private bool _saving;

    private void ToggleExpanded() => _expanded = !_expanded;

    private async Task UpdatePassword()
    {
        _message = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _message = "Current password is required.";
            _isError = true;
            return;
        }

        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword.Length < 8)
        {
            _message = "New password must be at least 8 characters.";
            _isError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _message = "New password and confirmation do not match.";
            _isError = true;
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _message = "Password updated successfully.";
            _isError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _message = $"Failed to update password: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

@if (Visible)
{
    <div class="modal-backdrop show"></div>
    <div class="modal show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="OnCancel"></button>
                </div>
                <div class="modal-body">
                    @if (Session is not null)
                    {
                        <p>
                            Are you sure you want to revoke the session on
                            <strong>@Session.Device</strong> from <strong>@Session.Location</strong>?
                        </p>
                        <p class="text-body-secondary mb-0">This will sign out the device immediately.</p>
                    }
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="OnCancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="OnConfirm">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }
}

