@code {
    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _message;
    private bool _isError;
    private bool _saving;

    private void ToggleExpanded() => _expanded = !_expanded;

    private async Task UpdatePassword()
    {
        _message = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _message = "Current password is required.";
            _isError = true;
            return;
        }

        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword.Length < 8)
        {
            _message = "New password must be at least 8 characters.";
            _isError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _message = "New password and confirmation do not match.";
            _isError = true;
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _message = "Password updated successfully.";
            _isError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _message = $"Failed to update password: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

