}

.preview-light {
    background-color: #ffffff;
    color: #212529;
}

.preview-dark {
    background-color: #1e1e2e;
    color: #e0e0e0;
}

.preview-header {
    margin-bottom: 0.5rem;
    padding-bottom: 0.5rem;
    border-bottom: 1px solid rgba(128, 128, 128, 0.3);
}

.preview-text {
    margin-bottom: 0.5rem;
}

.preview-nav {
    font-size: 0.9em;
    opacity: 0.7;
}

