@code {
    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfile();
        _loading = false;
    }

    private async Task LoadProfile()
    {
        _profile = await SettingsService.GetProfileAsync();
        ResetForm();
    }

    private void ResetForm()
    {
        if (_profile is null) return;
        _displayName = _profile.DisplayName;
        _email = _profile.Email;
        _bio = _profile.Bio;
    }

    private async Task SaveChanges()
    {
        if (_profile is null) return;
        _saving = true;
        _statusMessage = null;

        try
        {
            var updated = _profile with
            {
                DisplayName = _displayName,
                Email = _email,
                Bio = _bio
            };
            await SettingsService.SaveProfileAsync(updated);
            _profile = updated;
            _statusMessage = "Profile saved successfully!";
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardChanges()
    {
        ResetForm();
        _statusMessage = null;
    }
}

