toolArgs.file_text:
@inject ISettingsService SettingsService

@if (_loading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (_prefs is not null)
{
    @if (_statusMessage is not null)
    {
        <div class="alert alert-success alert-dismissible" role="alert">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <h6 class="mb-3">Notification Channels</h6>

    <div class="mb-3">
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="emailNotif"
                   checked="@_emailNotifications"
                   @onchange="e => _emailNotifications = (bool)e.Value!" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="pushNotif"
                   checked="@_pushNotifications"
                   @onchange="e => _pushNotifications = (bool)e.Value!" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="weeklyDigest"
                   checked="@_weeklyDigest"
                   @onchange="e => _weeklyDigest = (bool)e.Value!" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <hr />

    <h6 class="mb-3">Muted Channels</h6>
    <div class="mb-3">
        @foreach (var channel in _allChannels)
        {
            var isMuted = _mutedChannels.Contains(channel);
            <div class="form-check mb-2">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@isMuted"
                       @onchange="e => ToggleMute(channel, (bool)e.Value!)" />
                <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
            </div>
        }
    </div>

    <button class="btn btn-primary" @onclick="SavePreferences" disabled="@_saving">
        @if (_saving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>
}

@code {
    private static readonly string[] _allChannels =
        ["General", "Updates", "Marketing", "Support", "Engineering"];

    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;

    protected override async Task OnInitializedAsync()
    {
        _prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = _prefs.EmailNotifications;
        _pushNotifications = _prefs.PushNotifications;
        _weeklyDigest = _prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(_prefs.MutedChannels);
        _loading = false;
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        _saving = true;
        _statusMessage = null;

        try
        {
            var updated = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                _mutedChannels.ToList());

            await SettingsService.SaveNotificationPrefsAsync(updated);
            _prefs = updated;
            _statusMessage = "Notification preferences saved!";
        }
        finally
        {
            _saving = false;
        }
    }
}

