@inject ISettingsService SettingsService

@if (_loading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (_security is not null)
{
    <ChangePasswordPanel />

    <div class="card mb-3">
        <div class="card-body">
            <h6>Two-Factor Authentication</h6>
            <div class="d-flex align-items-center gap-3">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_twoFactorEnabled"
                           @onchange="Toggle2FA" />
                    <label class="form-check-label" for="twoFactor">
                        Enable Two-Factor Authentication
                    </label>
                </div>
                <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(_twoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
            @if (_security.LastPasswordChange.HasValue)
            {
                <div class="text-body-secondary small mt-2">
                    Last password change: @_security.LastPasswordChange.Value.ToString("MMMM d, yyyy")
                </div>
            }
        </div>
    </div>

    <div class="card">
        <div class="card-header">
            <h6 class="mb-0">Active Sessions</h6>
        </div>
        <div class="card-body p-0">
            <div class="table-responsive">
                <table class="table table-hover mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in _security.Sessions)
                        {
                            var isCurrent = session == _security.Sessions.FirstOrDefault();
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrent)
                                    {
                                        <span class="badge bg-primary ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (!isCurrent)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>
    </div>

    <RevokeSessionDialog Visible="_showRevokeDialog"
                         Session="_sessionToRevoke"
                         OnConfirm="ConfirmRevoke"
                         OnCancel="CancelRevoke" />
}

@code {
    private SecuritySettings? _security;
    private bool _twoFactorEnabled;
    private bool _loading = true;
    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        await LoadSecurity();
        _loading = false;
    }

    private async Task LoadSecurity()
    {
        _security = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = _security.TwoFactorEnabled;
    }

    private void Toggle2FA(ChangeEventArgs e)
    {
        _twoFactorEnabled = (bool)e.Value!;
    }

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            await LoadSecurity();
        }
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;

        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

